parameters.jsCode:
const error = $input.first().json;

const workflowName = error.workflow?.name || 'Unknown workflow';
const errorMessage = error.execution?.error?.message || 'Unknown error';
const errorStack = error.execution?.error?.stack || '';
const executionId = error.execution?.id || '';
const node = error.execution?.lastNodeExecuted || '';

// Try to extract customer phone from the failed execution data
let customerPhone = null;
try {
  const inputData = error.execution?.data?.executionData?.nodeExecutionStack?.[0]?.data?.main?.[0]?.[0]?.json;
  customerPhone = inputData?.customer_phone || inputData?.phone || null;
} catch(e) {}

return [{
  json: {
    workflowName,
    errorMessage,
    errorStack,
    executionId,
    node,
    customerPhone,
    timestamp: new Date().toISOString()
  }
}];

